/**
 * pdf-sheet-export.mjs — "Export to PDF" for Shadowdark player character sheets.
 *
 * Adds a small header button to every owned PlayerSheetSD that fills the
 * bundled form-fillable character sheet (assets/pdf/shadowdark-character-sheet.pdf,
 * generated by dev/pdf-sheet/generate-sheet.mjs) with the actor's data and hands
 * the user a saved / downloaded PDF.
 *
 * Field ids match assets/pdf/shadowdark-character-sheet-fields.json. Data comes
 * from the derived document (actor.system.abilities carries active effects like
 * an Ability Score Improvement) and the Shadowdark data model's own computed
 * getters — getAttacks / getSlotUsage / getTitle / getLanguageItems — which
 * give the same numbers the sheet shows WITHOUT invoking actor.sheet.getData()
 * (that enriches notes into a live document, a system-side XSS sink).
 */
import { MODULE_ID } from "../shared/module-id.mjs";

const TEMPLATE_PATH = `modules/${MODULE_ID}/assets/pdf/shadowdark-character-sheet.pdf`;
const PDFLIB_PATH = `modules/${MODULE_ID}/scripts/pdf-export/lib/pdf-lib.esm.min.js`;

let _pdflib = null;
/** Lazy-load the vendored pdf-lib ESM bundle (only when the user exports). */
async function getPdfLib() {
  if (_pdflib) return _pdflib;
  _pdflib = await import(foundry.utils.getRoute(PDFLIB_PATH));
  return _pdflib;
}

/* ---------------------------------------------------------------- helpers */

const cap = (s) => (s ? String(s)[0].toUpperCase() + String(s).slice(1) : "");
const fmtMod = (n) => (Number(n) >= 0 ? `+${Number(n)}` : `${Number(n)}`);
/** " + 4" / "d20 + 4" → "+4" / "d20+4" (collapse the display padding). */
const tightenFormula = (s) => String(s ?? "").replace(/\s+/g, "").replace(/^\+/, "+") || "";
const tightenBonus = (s) => {
  const t = String(s ?? "").replace(/\s+/g, "");
  if (!t) return "+0";
  return /^[+-]/.test(t) ? t : `+${t}`;
};

/** Resolve a deity / patron value that may be a bare string or a UUID. */
async function resolveName(v) {
  if (typeof v !== "string" || !v) return "";
  if (v.includes(".") && /^(Compendium|Actor|Item)\./.test(v)) {
    try { return (await fromUuid(v))?.name ?? ""; } catch { return ""; }
  }
  return v;
}

/** Strip HTML to plain text with newlines for the notes / features boxes.
 * Parsed in an INERT document (DOMParser) — never via innerHTML on a live
 * document — so a player's crafted notes (e.g. `<img onerror=…>`) cannot run
 * JS in the exporter's browser (a GM owns every actor and can export any).
 *
 * When no DOMParser is present (a node test harness), fall back to a textual
 * tag-strip: still inert (markup is never assigned to a live document, so no
 * script/handler can run), and it keeps the plain-text mapping unit-testable.
 * In the browser DOMParser is always defined, so the fallback never runs live. */
function htmlToText(html) {
  if (!html) return "";
  const Parser = globalThis.DOMParser;
  if (typeof Parser === "function") {
    const doc = new Parser().parseFromString(String(html), "text/html");
    doc.querySelectorAll("br").forEach((br) => br.replaceWith("\n"));
    doc.querySelectorAll("p, li, div, h1, h2, h3, h4").forEach((el) => el.append("\n"));
    return (doc.body?.textContent ?? "").replace(/\n{3,}/g, "\n\n").replace(/[ \t]+\n/g, "\n").trim();
  }
  return String(html)
    .replace(/<\s*(?:br|\/p|\/li|\/div|\/h[1-4])\s*\/?>/gi, "\n")
    .replace(/<[^>]*>/g, "")                       // drop every remaining tag (incl. <img onerror…>)
    .replace(/\n{3,}/g, "\n\n").replace(/[ \t]+\n/g, "\n").trim();
}

/** Concise, plain-text one-liner for a spell's notes cell — the first sentence
 * of the (inert-parsed) description, capped. Never HTML: the manifest declares
 * spell_*_notes as plain text fields, so we fill them with a safe summary
 * rather than injecting markup. */
function spellSummary(spell) {
  const text = htmlToText(spell?.system?.description);
  if (!text) return "";
  const firstLine = text.split("\n").map((l) => l.trim()).filter(Boolean)[0] ?? "";
  const sentence = (firstLine.split(/(?<=[.!?])\s/)[0] ?? firstLine).trim();
  return sentence.length > 140 ? `${sentence.slice(0, 137).trimEnd()}…` : sentence;
}

/** Human label for a range slug, via the system's own maps (nearLine → "Near
 * Line", doubleNear → "Double Near") with a Capitalize fallback. */
const rangeLabel = (r) => {
  if (!r) return "";
  const cfg = globalThis.CONFIG?.SHADOWDARK;
  return cfg?.RANGES?.[r] ?? cfg?.SPELL_RANGES?.[r] ?? cap(r);
};

/** Human label for a spell duration. Focus/instant/permanent are shown as the
 * bare label (their numeric value is not meaningful); counted types keep it. */
const NON_NUMERIC_DURATION = new Set(["focus", "instant", "permanent"]);
const durationLabel = (d) => {
  if (!d) return "";
  const type = d.type ?? "";
  const label = globalThis.CONFIG?.SHADOWDARK?.DURATION_TYPES?.[type] ?? cap(type);
  const value = Number(d.value);
  if (NON_NUMERIC_DURATION.has(type) || !Number.isFinite(value) || value <= 0) return label;
  return `${value} ${label}`;
};

const PHYSICAL_TYPES = new Set(["Weapon", "Armor", "Basic", "Potion", "Scroll", "Wand", "Gem"]);
const isTrinket = (item) => /trinket/i.test(item?.name ?? "");
/** Effective slots an item occupies (0 ⇒ free to carry). */
function itemSlotCount(item) {
  const s = item?.system?.slots;
  if (!s) return 0;
  const qty = item.system?.quantity ?? 1;
  const per = s.per_slot || 1;
  const free = s.free_carry ?? 0;
  const used = s.slots_used ?? 1;
  return Math.max(0, Math.ceil(qty / per) - free) * used;
}
/** A carried item is "free to carry" when it costs no slots or is a trinket. */
function isFreeCarry(item) {
  if (isTrinket(item)) return true;
  const s = item?.system?.slots;
  if (!s) return false;
  return (s.slots_used ?? 0) === 0 || itemSlotCount(item) === 0;
}
function gearLine(item) {
  let line = item.name;
  const qty = item.system?.quantity ?? 1;
  if (qty > 1) line += ` (x${qty})`;
  const slots = itemSlotCount(item);
  if (slots > 1) line += ` — ${slots} slots`;
  return line;
}

/* --------------------------------------------------------- field building */

/**
 * Map an actor to { text: {id: value}, checks: {id: bool} } keyed by the PDF
 * template's field ids. Async because it resolves ancestry/class/deity UUIDs.
 *
 * Data is sourced from the Shadowdark data model's own computed getters
 * (getAttacks / getSlotUsage / getTitle / getLanguageItems) plus the derived
 * document — deliberately NOT actor.sheet.getData(), because that enriches the
 * actor's notes into a live document (a system-side sink that runs `<img
 * onerror>` style payloads), and because getData()'s abilities are the
 * pre-active-effect source values.
 */
export async function buildFieldValues(actor) {
  const sys = actor.system ?? {};
  // These model getters may be sync or async — await handles both.
  const call = async (name, fallback) => {
    try { const fn = sys[name]; return typeof fn === "function" ? await fn.call(sys) : fallback; }
    catch (e) { console.warn(`${MODULE_ID} | PDF export: ${name}() failed`, e); return fallback; }
  };
  const attackData = await call("getAttacks", {});
  const slotUsage = await call("getSlotUsage", {});
  const title = await call("getTitle", sys.title ?? "");
  const langItems = await call("getLanguageItems", []);

  const text = {};
  const checks = {};
  const T = (id, v) => { text[id] = v == null ? "" : String(v); };
  const C = (id, v) => { checks[id] = !!v; };

  const level = sys.level?.value ?? 1;

  /* identity — ancestry/class/background/deity are UUID refs on the model */
  T("name", actor.name);
  T("level", level);
  T("xp", sys.level?.xp ?? 0);
  T("xp_next", level * 10);
  // Luck is a numeric field on the sheet now (was a checkbox): show the token
  // count from the pulp-mode variant, falling back to 1 for the base
  // single-token rule. Leave the box blank when they have no luck.
  const luckCount = sys.luck?.remaining || (sys.luck?.available ? 1 : 0);
  T("luck", luckCount || "");
  const classDoc = sys.class ? await fromUuid(sys.class).catch(() => null) : null;
  T("ancestry", await resolveName(sys.ancestry));
  T("class", classDoc?.name ?? (await resolveName(sys.class)));
  T("alignment", cap(sys.alignment));
  T("background", await resolveName(sys.background));
  T("deity", (await resolveName(sys.deity)) || (await resolveName(sys.patron)));
  T("title", title || "");

  /* abilities — DERIVED document values (include active effects) */
  for (const k of ["str", "dex", "con", "int", "wis", "cha"]) {
    const a = sys.abilities?.[k] ?? {};
    const value = a.value ?? 0;
    const mod = a.mod ?? Math.floor((value - 10) / 2);
    T(k, value);
    T(`${k}_mod`, fmtMod(mod));
  }

  /* hp / ac */
  T("hp", sys.attributes?.hp?.value);
  T("hp_max", sys.attributes?.hp?.max);
  T("ac", sys.attributes?.ac?.value);

  /* attacks — the model's own computed roll formulas. getAttacks() returns
   * { melee, ranged, … } buckets; keep the standard melee→ranged order, then
   * append any OTHER array buckets (custom attack types) instead of silently
   * dropping them. */
  const attacks = [
    ...(Array.isArray(attackData?.melee) ? attackData.melee : []),
    ...(Array.isArray(attackData?.ranged) ? attackData.ranged : []),
  ];
  for (const [k, v] of Object.entries(attackData ?? {})) {
    if (k === "melee" || k === "ranged" || !Array.isArray(v)) continue;
    attacks.push(...v);
  }
  attacks.slice(0, 5).forEach((att, i) => {
    const r = i + 1;
    // Prefer the already-resolved item on the attack entry (getAttacks attaches
    // it), fall back to a UUID lookup, then the entry's own name/label.
    const weapon = att.item ?? (att.itemUuid ? fromUuidSync?.(att.itemUuid) : null);
    T(`attack_${r}_name`, weapon?.name ?? att.name ?? att.label ?? "");
    T(`attack_${r}_bonus`, tightenBonus(att.mainRoll?.bonus));
    T(`attack_${r}_damage`, tightenFormula(att.damageRoll?.formula));
    T(`attack_${r}_range`, rangeLabel(att.attack?.range ?? att.range ?? ""));
  });

  /* talents & languages */
  const talents = actor.items.filter((i) => i.type === "Talent");
  T("talents", talents.map((i) => `- ${i.name}`).join("\n"));
  const langs = (langItems ?? []).map((l) => l?.name).filter(Boolean);
  T("languages", (langs.length ? langs : actor.items.filter((i) => i.type === "Language").map((i) => i.name)).join(", "));

  /* gear — every physical item carried (equipped, treasure and gems included,
   * since they all occupy slots), minus stashed; trinkets / 0-slot ⇒ free. */
  const carried = actor.items.filter((i) => PHYSICAL_TYPES.has(i.type) && !i.system?.stashed);
  const freeItems = carried.filter(isFreeCarry);
  const slotItems = carried.filter((i) => !isFreeCarry(i));
  slotItems.slice(0, 20).forEach((i, idx) => T(`gear_${idx + 1}`, gearLine(i)));
  const overflow = slotItems.slice(20).map(gearLine);
  T("gear_slots_used", slotUsage?.total ?? slotItems.reduce((n, i) => n + itemSlotCount(i), 0));
  T("gear_slots_max", sys.slots ?? Math.max(sys.abilities?.str?.value ?? 10, 10));
  T("gp", sys.coins?.gp ?? 0);
  T("sp", sys.coins?.sp ?? 0);
  T("cp", sys.coins?.cp ?? 0);
  T("free_carry", freeItems.map(gearLine).join("\n"));

  /* page 2 — spells. Caster ability comes from the class doc's spellcasting. */
  const casterAbility = classDoc?.system?.spellcasting?.ability ?? "";
  if (casterAbility && casterAbility !== "none" && sys.abilities?.[casterAbility]) {
    T("spellcasting_stat", casterAbility.toUpperCase());
    T("spellcasting_mod", fmtMod(sys.abilities[casterAbility].mod ?? 0));
  }
  const spells = actor.items.filter((i) => i.type === "Spell")
    .sort((a, b) => ((a.system?.tier ?? 0) - (b.system?.tier ?? 0)) || a.name.localeCompare(b.name));
  spells.slice(0, 16).forEach((s, i) => {
    const r = i + 1;
    T(`spell_${r}_name`, s.name);
    T(`spell_${r}_tier`, s.system?.tier ?? "");
    T(`spell_${r}_range`, rangeLabel(s.system?.range));
    T(`spell_${r}_duration`, durationLabel(s.system?.duration));
    // The template declares spell_*_notes — fill it with a safe, concise
    // plain-text summary (never HTML) so the column isn't left blank.
    T(`spell_${r}_notes`, spellSummary(s));
    C(`spell_${r}_lost`, s.system?.lost);
  });

  /* features + notes — class/ancestry are UUID refs (or a getData doc), NOT
   * embedded items, so source the names the same way the header fields did. */
  const features = [];
  const ancName = text.ancestry;
  if (ancName) {
    const anc = talents.filter((i) => i.system?.talentClass === "ancestry").map((i) => i.name);
    features.push(`Ancestry: ${ancName}${anc.length ? ` — ${anc.join(", ")}` : ""}`);
  }
  const clsName = text.class;
  if (clsName) {
    const cls = talents.filter((i) => i.system?.talentClass !== "ancestry").map((i) => i.name);
    const hd = classDoc?.system?.hitPoints ? ` (hit die ${classDoc.system.hitPoints})` : "";
    features.push(`Class: ${clsName}${hd}${cls.length ? ` — ${cls.join(", ")}` : ""}`);
  }
  T("features", features.join("\n"));
  const notes = [];
  const acTip = sys.attributes?.ac?.tooltips;
  if (acTip) notes.push(`AC ${sys.attributes.ac.value} = ${acTip}`);
  const bio = htmlToText(sys.notes);
  if (bio) notes.push(bio);
  if (overflow.length) notes.push(`Gear overflow (no line): ${overflow.join("; ")}`);
  if (attacks.length > 5) notes.push(`+${attacks.length - 5} more attack(s) not shown above.`);
  if (spells.length > 16) notes.push(`+${spells.length - 16} more spell(s) not shown above.`);
  T("notes", notes.join("\n"));

  return { text, checks };
}

/* ------------------------------------------------------------------- fill */

/** Fill the template PDF from an actor and return the saved bytes. */
export async function fillActorPdf(actor) {
  const PDFLib = await getPdfLib();
  const res = await fetch(foundry.utils.getRoute(TEMPLATE_PATH));
  if (!res.ok) throw new Error(`character-sheet template not found (${res.status})`);
  const pdfDoc = await PDFLib.PDFDocument.load(await res.arrayBuffer());
  const form = pdfDoc.getForm();

  const { text, checks } = await buildFieldValues(actor);
  for (const [id, value] of Object.entries(text)) {
    try { form.getTextField(id).setText(value); }
    catch (e) { console.warn(`${MODULE_ID} | PDF export: text field "${id}" missing`, e); }
  }
  for (const [id, on] of Object.entries(checks)) {
    try { const f = form.getCheckBox(id); on ? f.check() : f.uncheck(); }
    catch (e) { console.warn(`${MODULE_ID} | PDF export: checkbox "${id}" missing`, e); }
  }
  return pdfDoc.save();
}

/* ------------------------------------------------------------------- save */

export async function exportActorToPdf(actor) {
  if (!actor) return;
  ui.notifications?.info(`Exporting ${actor.name} to PDF…`);
  try {
    const bytes = await fillActorPdf(actor);
    const safe = actor.name.replace(/[\s\\/:*?"<>|]+/g, "_").replace(/^_+|_+$/g, "") || "character";
    const filename = `${safe} - Shadowdark.pdf`;

    const download = () => {
      const blob = new Blob([bytes], { type: "application/pdf" });
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = filename;
      document.body.appendChild(a);
      a.click();
      a.remove();
      setTimeout(() => URL.revokeObjectURL(url), 1000);
      ui.notifications?.info(`Downloaded ${filename}`);
    };

    // Native "Save As" (Electron / Chromium / Edge). On anything other than the
    // user cancelling — SecurityError in a cross-origin iframe, expired user
    // activation — fall through to the plain download rather than hard-failing.
    if (typeof window.showSaveFilePicker === "function") {
      try {
        const handle = await window.showSaveFilePicker({
          suggestedName: filename,
          types: [{ description: "PDF Document", accept: { "application/pdf": [".pdf"] } }],
        });
        const writable = await handle.createWritable();
        await writable.write(bytes);
        await writable.close();
        ui.notifications?.info(`Saved ${filename}`);
        return;
      } catch (err) {
        if (err.name === "AbortError") return; // user cancelled
        console.warn(`${MODULE_ID} | PDF export: save picker failed, downloading instead`, err);
      }
    }
    download();
  } catch (err) {
    console.error(`${MODULE_ID} | PDF export failed`, err);
    ui.notifications?.error(`PDF export failed: ${err.message}`);
  }
}

/* --------------------------------------------------------- test internals */

/** Pure helpers exposed for node tests (no public API surface). */
export const _internals = {
  htmlToText, spellSummary, itemSlotCount, isFreeCarry, gearLine,
  rangeLabel, durationLabel, fmtMod, tightenBonus, tightenFormula,
};

/* --------------------------------------------------------------- register */

export const PdfSheetExport = {
  /** Add the export header button to owned Shadowdark player sheets. */
  register() {
    Hooks.on("getPlayerSheetSDHeaderButtons", (app, buttons) => {
      const actor = app?.actor ?? app?.document;
      if (!actor || actor.type !== "Player" || !actor.isOwner) return;
      if (buttons.some((b) => b.class === "sde-pdf-export")) return;
      buttons.unshift({
        label: "PDF",
        class: "sde-pdf-export",
        icon: "fa-solid fa-file-pdf",
        onclick: () => exportActorToPdf(actor),
      });
    });
  },
};
